var todoListHTML = []byte("<!doctype html>\n<html lang=\"en\">\n\t<head>\n\t\t<meta charset=\"UTF-8\" />\n\t\t<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n\t\t<title>Todo List</title>\n\t\t<style>\n\t\t\t.island-todo {\n\t\t\t\twidth: 320px;\n\t\t\t\tfont-family: ui-sans-serif, system-ui, sans-serif;\n\t\t\t\tbackground: #ffffff;\n\t\t\t\tborder-radius: 14px;\n\t\t\t\tbox-shadow: 0 10px 30px rgba(15, 23, 42, 0.12);\n\t\t\t\toverflow: hidden;\n\t\t\t}\n\t\t\t.island-todo header {\n\t\t\t\tdisplay: flex;\n\t\t\t\talign-items: center;\n\t\t\t\tjustify-content: space-between;\n\t\t\t\tpadding: 14px 16px;\n\t\t\t\tbackground: #0f172a;\n\t\t\t\tcolor: #f8fafc;\n\t\t\t}\n\t\t\t.island-todo header h2 {\n\t\t\t\tmargin: 0;\n\t\t\t\tfont-size: 15px;\n\t\t\t\tfont-weight: 600;\n\t\t\t}\n\t\t\t.island-todo header .badge {\n\t\t\t\tfont-size: 12px;\n\t\t\t\tbackground: #334155;\n\t\t\t\tpadding: 2px 8px;\n\t\t\t\tborder-radius: 999px;\n\t\t\t\tcolor: #cbd5e1;\n\t\t\t}\n\t\t\t.island-todo form {\n\t\t\t\tdisplay: flex;\n\t\t\t\tgap: 8px;\n\t\t\t\tpadding: 12px 16px;\n\t\t\t\tborder-bottom: 1px solid #e2e8f0;\n\t\t\t}\n\t\t\t.island-todo input[type=\"text\"] {\n\t\t\t\tflex: 1;\n\t\t\t\tpadding: 8px 10px;\n\t\t\t\tborder: 1px solid #cbd5e1;\n\t\t\t\tborder-radius: 8px;\n\t\t\t\tfont-size: 14px;\n\t\t\t\toutline: none;\n\t\t\t}\n\t\t\t.island-todo input[type=\"text\"]:focus {\n\t\t\t\tborder-color: #6366f1;\n\t\t\t}\n\t\t\t.island-todo form button {\n\t\t\t\tborder: none;\n\t\t\t\tbackground: #6366f1;\n\t\t\t\tcolor: white;\n\t\t\t\tpadding: 8px 14px;\n\t\t\t\tborder-radius: 8px;\n\t\t\t\tfont-size: 14px;\n\t\t\t\tfont-weight: 600;\n\t\t\t\tcursor: pointer;\n\t\t\t}\n\t\t\t.island-todo form button:hover {\n\t\t\t\tbackground: #4f46e5;\n\t\t\t}\n\t\t\t.island-todo ul {\n\t\t\t\tlist-style: none;\n\t\t\t\tmargin: 0;\n\t\t\t\tpadding: 6px 0;\n\t\t\t\tmax-height: 240px;\n\t\t\t\toverflow-y: auto;\n\t\t\t}\n\t\t\t.island-todo li {\n\t\t\t\tdisplay: flex;\n\t\t\t\talign-items: center;\n\t\t\t\tgap: 10px;\n\t\t\t\tpadding: 8px 16px;\n\t\t\t\tfont-size: 14px;\n\t\t\t\tcolor: #1e293b;\n\t\t\t}\n\t\t\t.island-todo li:hover {\n\t\t\t\tbackground: #f8fafc;\n\t\t\t}\n\t\t\t.island-todo li .check {\n\t\t\t\twidth: 18px;\n\t\t\t\theight: 18px;\n\t\t\t\tborder: 2px solid #cbd5e1;\n\t\t\t\tborder-radius: 5px;\n\t\t\t\tcursor: pointer;\n\t\t\t\tflex-shrink: 0;\n\t\t\t\tdisplay: grid;\n\t\t\t\tplace-items: center;\n\t\t\t}\n\t\t\t.island-todo li.done .check {\n\t\t\t\tbackground: #22c55e;\n\t\t\t\tborder-color: #22c55e;\n\t\t\t\tcolor: white;\n\t\t\t}\n\t\t\t.island-todo li.done .text {\n\t\t\t\ttext-decoration: line-through;\n\t\t\t\tcolor: #94a3b8;\n\t\t\t}\n\t\t\t.island-todo li .text {\n\t\t\t\tflex: 1;\n\t\t\t}\n\t\t\t.island-todo li .del {\n\t\t\t\tborder: none;\n\t\t\t\tbackground: transparent;\n\t\t\t\tcolor: #cbd5e1;\n\t\t\t\tcursor: pointer;\n\t\t\t\tfont-size: 16px;\n\t\t\t}\n\t\t\t.island-todo li .del:hover {\n\t\t\t\tcolor: #ef4444;\n\t\t\t}\n\t\t\t.island-todo footer {\n\t\t\t\tpadding: 8px 16px;\n\t\t\t\tfont-size: 12px;\n\t\t\t\tcolor: #94a3b8;\n\t\t\t\tborder-top: 1px solid #e2e8f0;\n\t\t\t}\n\t\t</style>\n\t</head>\n\t<body>\n\t\t<!-- 1. Root mount — placeholder DOM, replaced at runtime. -->\n\t\t<div id=\"island-root\">\n\t\t\t<div class=\"island-todo\">\n\t\t\t\t<header>\n\t\t\t\t\t<h2>Today</h2>\n\t\t\t\t\t<span class=\"badge\">0 / 0</span>\n\t\t\t\t</header>\n\t\t\t\t<form>\n\t\t\t\t\t<input type=\"text\" placeholder=\"Add a task…\" />\n\t\t\t\t\t<button>Add</button>\n\t\t\t\t</form>\n\t\t\t\t<ul>\n\t\t\t\t\t<li class=\"done\">\n\t\t\t\t\t\t<span class=\"check\">✓</span>\n\t\t\t\t\t\t<span class=\"text\">write tests</span>\n\t\t\t\t\t\t<button class=\"del\">×</button>\n\t\t\t\t\t</li>\n\t\t\t\t</ul>\n\t\t\t\t<footer>0 of 0 done</footer>\n\t\t\t</div>\n\t\t</div>\n\n\t\t<!-- 2. Schema → becomes Go struct. -->\n\t\t<script type=\"application/schema+json\" id=\"island-schema\">\n\t\t\t{\n\t\t\t\t\"type\": \"object\",\n\t\t\t\t\"properties\": {\n\t\t\t\t\t\"title\": { \"type\": \"string\", \"tag\": \"title\" },\n\t\t\t\t\t\"items\": {\n\t\t\t\t\t\t\"type\": \"array\",\n\t\t\t\t\t\t\"tag\": \"items\",\n\t\t\t\t\t\t\"items\": {\n\t\t\t\t\t\t\t\"type\": \"object\",\n\t\t\t\t\t\t\t\"properties\": {\n\t\t\t\t\t\t\t\t\"text\": { \"type\": \"string\", \"tag\": \"text\" },\n\t\t\t\t\t\t\t\t\"done\": { \"type\": \"boolean\", \"tag\": \"done\" }\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t}\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t}\n\t\t</script>\n\n\t\t<!-- 3. Data island — placeholder JSON in source. -->\n\t\t<script type=\"application/json\" id=\"island-data\">\n\t\t\t{\n\t\t\t\t\"title\": \"Today\",\n\t\t\t\t\"items\": [\n\t\t\t\t\t{ \"text\": \"write tests\", \"done\": true },\n\t\t\t\t\t{ \"text\": \"ship it\", \"done\": false },\n\t\t\t\t\t{ \"text\": \"celebrate\", \"done\": false }\n\t\t\t\t]\n\t\t\t}\n\t\t</script>\n\n\t\t<!-- 4. Render script — pure client, rewrites #island-root. -->\n\t\t<script type=\"module\" data-island-render>\n\t\t\tconst data = JSON.parse(\n\t\t\t\tdocument.getElementById(\"island-data\").textContent,\n\t\t\t);\n\t\t\tconst root = document.getElementById(\"island-root\");\n\n\t\t\tlet state = { title: data.title, items: [...data.items] };\n\n\t\t\tfunction doneCount() {\n\t\t\t\treturn state.items.filter((i) => i.done).length;\n\t\t\t}\n\n\t\t\tfunction render() {\n\t\t\t\tconst items = state.items\n\t\t\t\t\t.map(\n\t\t\t\t\t\t(item, i) => `\n\t\t\t\t\t\t<li class=\"${item.done ? \"done\" : \"\"}\">\n\t\t\t\t\t\t\t<span class=\"check\" data-toggle=\"${i}\">${item.done ? \"✓\" : \"\"}</span>\n\t\t\t\t\t\t\t<span class=\"text\">${item.text}</span>\n\t\t\t\t\t\t\t<button class=\"del\" data-del=\"${i}\">×</button>\n\t\t\t\t\t\t</li>\n\t\t\t\t\t`,\n\t\t\t\t\t)\n\t\t\t\t\t.join(\"\");\n\n\t\t\t\troot.innerHTML = `\n\t\t\t\t\t<div class=\"island-todo\">\n\t\t\t\t\t\t<header>\n\t\t\t\t\t\t\t<h2>${state.title}</h2>\n\t\t\t\t\t\t\t<span class=\"badge\">${doneCount()} / ${state.items.length}</span>\n\t\t\t\t\t\t</header>\n\t\t\t\t\t\t<form>\n\t\t\t\t\t\t\t<input type=\"text\" placeholder=\"Add a task…\" />\n\t\t\t\t\t\t\t<button>Add</button>\n\t\t\t\t\t\t</form>\n\t\t\t\t\t\t<ul>${items}</ul>\n\t\t\t\t\t\t<footer>${doneCount()} of ${state.items.length} done</footer>\n\t\t\t\t\t</div>\n\t\t\t\t`;\n\t\t\t\troot.querySelector(\"input\")?.focus();\n\t\t\t}\n\n\t\t\troot.addEventListener(\"click\", (e) => {\n\t\t\t\tconst t = e.target;\n\t\t\t\tconst toggle = t?.dataset?.toggle;\n\t\t\t\tconst del = t?.dataset?.del;\n\t\t\t\tif (toggle !== undefined) {\n\t\t\t\t\tstate.items[toggle].done = !state.items[toggle].done;\n\t\t\t\t\trender();\n\t\t\t\t}\n\t\t\t\tif (del !== undefined) {\n\t\t\t\t\tstate.items.splice(del, 1);\n\t\t\t\t\trender();\n\t\t\t\t}\n\t\t\t});\n\n\t\t\troot.addEventListener(\"submit\", (e) => {\n\t\t\t\te.preventDefault();\n\t\t\t\tconst input = root.querySelector(\"input[type=text]\");\n\t\t\t\tconst text = input.value.trim();\n\t\t\t\tif (!text) return;\n\t\t\t\tstate.items.push({ text, done: false });\n\t\t\t\trender();\n\t\t\t});\n\n\t\t\trender();\n\t\t</script>\n\t</body>\n</html>\n")

// RenderTodoList writes the TodoList island HTML to w with the island-data
// placeholder replaced by the marshaled form of d.
func RenderTodoList(w io.Writer, d TodoListData) error {
	blob, err := json.Marshal(d)
	if err != nil {
		return err
	}
	return injectIsland(w, todoListHTML, blob, 3732, 3921)
}

// injectIsland writes html to w with the bytes between
// [openEnd, closeStart) replaced by blob. openEnd and closeStart
// are the absolute byte offsets of the island-data slot's opening
// tag end and closing tag start, computed at codegen time.
func injectIsland(w io.Writer, html, blob []byte, openEnd, closeStart int) error {
	if openEnd < 0 || closeStart < 0 || openEnd > closeStart || closeStart > len(html) {
		return fmt.Errorf("islandc: invalid island-data splice bounds")
	}
	if _, err := w.Write(html[:openEnd]); err != nil {
		return err
	}
	if _, err := w.Write(blob); err != nil {
		return err
	}
	_, err := w.Write(html[closeStart:])
	return err
}
